int k = 1, ans; //报数kwhile(q.empty()!=1){ //循环队列非空  if(k % m != 0){ //不是m的倍数     q.push(q.front());      q.pop();   }  //报数m且次数大于1  else if(k%m==0&&q.front().times>1){     q.front().times--;     q.push(q.front());     q.pop();  }else{ //报数m且次数只有1     ans = q.front().id;     q.pop();  }   k++;     } cout << ans;  return 0;}
