先序加中序构建二叉树执行流程
int p=0;
int getTree(int pl,int pr,int ml,int mr){
    if(ml>mr) return -1;
    int t=p++;    
    BTree[t].data=pre[pl];
    int i=ml;
    while(i<=mr&&pre[pl]!=mid[i]) i++;
    int len=i-ml;
    BTree[t].left=getTree(pl+1,pl+len,ml,i-1);
    BTree[t].right=getTree(pl+len+1,pr,i+1,mr);
    return t;
}
